import React, { useState, useEffect } from 'react';

const OpenIDConnect = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const config = {
    clientId: process.env.REACT_APP_OIDC_CLIENT_ID,
    redirectUri: `${window.location.origin}/callback`,
    authorizationEndpoint: process.env.REACT_APP_OIDC_AUTHORIZATION_ENDPOINT,
    tokenEndpoint: process.env.REACT_APP_OIDC_TOKEN_ENDPOINT,
    logoutEndpoint: process.env.REACT_APP_OIDC_LOGOUT_ENDPOINT,
    scope: 'openid profile email'
  };

  const generateState = () => {
    return btoa(Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15));
  };

  const storeState = (state) => {
    sessionStorage.setItem('oidc_state', state);
  };

  const validateState = (state) => {
    const storedState = sessionStorage.getItem('oidc_state');
    if (!storedState || storedState !== state) {
      throw new Error('Invalid state parameter');
    }
    sessionStorage.removeItem('oidc_state');
    return true;
  };

  const decodeToken = (token) => {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(atob(base64).split('').map(c => {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));
      return JSON.parse(jsonPayload);
    } catch (e) {
      console.error('Error decoding token:', e);
      return null;
    }
  };

  const login = () => {
    const state = generateState();
    storeState(state);
    
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: config.clientId,
      redirect_uri: config.redirectUri,
      scope: config.scope,
      state: state
    });
    
    window.location.href = `${config.authorizationEndpoint}?${params.toString()}`;
  };

  const handleCallback = async () => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    
    if (!code) {
      setError('Authorization code not found');
      return;
    }
    
    try {
      validateState(state);
      
      const tokenResponse = await fetch(config.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${config.clientId}:${process.env.REACT_APP_OIDC_CLIENT_SECRET}`)
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: config.redirectUri
        })
      });
      
      if (!tokenResponse.ok) {
        throw new Error('Token exchange failed');
      }
      
      const tokens = await tokenResponse.json();
      const idToken = decodeToken(tokens.id_token);
      
      if (!idToken) {
        throw new Error('Failed to decode ID token');
      }
      
      setUser({
        ...idToken,
        accessToken: tokens.access_token,
        refreshToken: tokens.refresh_token
      });
      
      // Remove code and state from URL
      window.history.replaceState({}, document.title, window.location.pathname);
      
    } catch (err) {
      setError(err.message);
      console.error('Authentication error:', err);
    }
  };

  const logout = () => {
    const logoutUrl = new URL(config.logoutEndpoint);
    logoutUrl.searchParams.append('client_id', config.clientId);
    logoutUrl.searchParams.append('post_logout_redirect_uri', config.redirectUri);
    
    setUser(null);
    window.location.href = logoutUrl.toString();
  };

  useEffect(() => {
    if (window.location.pathname === '/callback') {
      handleCallback();
    }
  }, []);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  return (
    <div>
      {!user ? (
        <button onClick={login}>Login</button>
      ) : (
        <div>
          <p>Welcome, {user.name || user.email}</p>
          <button onClick={logout}>Logout</button>
        </div>
      )}
    </div>
  );
};

export default OpenIDConnect;